#include <iostream>#include <algorithm>#define ll long longusing namespace std;ll gcd(ll a, ll b) {    while (b != 0) {        ll temp = b;        b = a % b;        a = temp;    }    return a;}ll lcm(ll a, ll b, ll m) {    if (a == 0 || b == 0) return 0;    ll g = gcd(a, b);    ll a_reduced = a / g;   if (b > 0 && a_reduced > m / b) {        return m + 1;     }    return a_reduced * b;} int main() {    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin >> t;        while (t--) {        ll a, b, c, m;        cin >> a >> b >> c >> m;        ll lab = lcm(a, b, m);        ll lac = lcm(a, c, m);        ll lbc = lcm(b, c, m);        ll labc =lcm(lab, c, m);         ll v_abc = m / labc;        ll v_ab = (m / lab) - v_abc;        ll v_ac = (m / lac) - v_abc;        ll v_bc = (m / lbc) - v_abc;         ll v_a = (m / a) - v_ab - v_ac - v_abc;        ll v_b = (m / b) - v_ab - v_bc - v_abc;        ll v_c = (m / c) - v_ac - v_bc - v_abc;         ll total_a = v_a *6 + v_ab *3 + v_ac *3 + v_abc *2;        ll total_b = v_b *6 + v_ab *3 + v_bc *3 + v_abc *2;        ll total_c = v_c *6 + v_ac *3 + v_bc *3 + v_abc *2;        cout <<total_a<<" "<<total_b<<" "<<total_c<< "\n";    }    return 0;}